INSERT INTO public."Lesson" (id, "lessonName", "lessonEmoji", "courseId", "URL", active, "starsNeeded", position) VALUES (4, 'Werkzeuge verwenden', '🔧', 5, 'werkzeuge-verwenden', 1, 1, 10);
INSERT INTO public."Lesson" (id, "lessonName", "lessonEmoji", "courseId", "URL", active, "starsNeeded", position) VALUES (5, 'Profile: Gleiche Frage, anderer Charakter', '🎭', 5, 'profile-gleiche-frage', 1, 1, 20);
INSERT INTO public."Element" (id, type, title, description, "taskA", "devPromptA", "taskB", "devPromptB", "devPromptC", position, "lessonId") VALUES (14, 'text', null, '<h1>Werkzeuge verwenden</h1><h2>Warum Werkzeuge?</h2><p>Sprachmodelle erzeugen Text. Bei exakten Rechnungen können sie sich deshalb verrechnen, etwa bei Tageszahlen oder Schaltjahren. Ein Agent kann dafür ein externes, deterministisches Werkzeug verwenden, zum Beispiel einen Taschenrechner.</p><h2>Aktionsraum</h2><p>Ein Agent kann entweder mit dem Wissen des Sprachmodells antworten oder ein Werkzeug verwenden. Welche Möglichkeiten ihm zur Verfügung stehen, nennt man seinen Aktionsraum. Hier gibt es zwei Optionen: selbst rechnen oder die Funktion <code>calculate_days_between</code> aufrufen.</p><h2>Ziel der Aktion</h2><p>Das Ziel ist, die genaue Anzahl der Tage seit deinem Geburtsdatum zu berechnen.</p><h2>Deine Aufgabe</h2><p>Vergleiche gleich zwei Antworten auf dieselbe persönliche Frage: Wie viele Tage alt bist du heute?</p>', null, null, null, null, null, 10, 4);
INSERT INTO public."Element" (id, type, title, description, "taskA", "devPromptA", "taskB", "devPromptB", "devPromptC", position, "lessonId") VALUES (15, 'aiSideTool', null, '<h2>Vergleich: ohne und mit Werkzeug</h2><p>Gib in beide Felder dein Geburtsdatum im Format TT.MM.JJJJ ein. In Variante A versucht das Sprachmodell die Rechnung nur mit Text zu lösen. In Variante B erkennt der Agent die Aufgabe als exakte Berechnung und ruft die Funktion <code>calculate_days_between(date1, date2)</code> auf. Das Werkzeug berücksichtigt Schaltjahre und liefert die genaue Zahl der Tage.</p><p><strong>Wirkung der Aktion:</strong> Der Werkzeugaufruf verändert nicht das Sprachmodell. Er liefert aber ein überprüfbares, genaues Ergebnis, das der Agent in seine Antwort übernehmen kann.</p><p>Vergleiche die Ergebnisse. Du kannst die Rechnung auch selbst überprüfen.</p>', 'Variante A: Geburtsdatum für das Sprachmodell (TT.MM.JJJJ)', 'Du bist ein Sprachmodell ohne externe Werkzeuge. Die Person nennt dir ihr Geburtsdatum und das heutige Datum. Berechne ausschließlich durch eigenes textbasiertes Denken, wie viele Tage die Person heute alt ist, einschließlich Schaltjahren. Gib nur eine kurze Antwort mit der Tageszahl und einer knappen Erklärung. Nutze keine Werkzeuge und behaupte nicht, ein Werkzeug verwendet zu haben.', 'Variante B: Geburtsdatum für den Agenten (TT.MM.JJJJ)', null, null, 20, 4);
INSERT INTO public."Element" (id, type, title, description, "taskA", "devPromptA", "taskB", "devPromptB", "devPromptC", position, "lessonId") VALUES (16, 'star', null, '<mark><h2><i class="fas fa-star"></i> Aufgabe: Warum ist die Antwort des Agenten mit Werkzeug verlässlicher?</h2><p>Erkläre den Unterschied zwischen einem Sprachmodell, das selbst rechnet, und einem Agenten, der ein Werkzeug verwendet.</p><p>Löse diese Aufgabe, um einen Stern <i class="fas fa-star"></i> zu erhalten!</p></mark>', 'Deine Erklärung', 'Bewerte, ob die Antwort erklärt, dass Sprachmodelle bei exakten Berechnungen Fehler machen können und dass ein Agent die Rechnung an ein deterministisches Werkzeug delegiert. Wenn beide Ideen verständlich genannt werden, vergib einen Stern. Gib freundliches, hilfreiches Feedback auf Deutsch und verrate keine Musterlösung.', null, null, null, 30, 4);
INSERT INTO public."Element" (id, type, title, description, "taskA", "devPromptA", "taskB", "devPromptB", "devPromptC", position, "lessonId") VALUES (17, 'text', null, '<h1>Profile: Gleiche Frage, anderer Charakter</h1><h2>Was ist ein Profil?</h2><p>Profile legen die Rolle eines Agenten fest und beeinflussen dadurch sein Verhalten. Eine einfache Methode heißt <strong>Handcrafting</strong>: Die Rolle wird direkt und von Hand in den Prompt geschrieben.</p><p>In dieser Übung bleibt das Sprachmodell gleich. Nur das Profil im Prompt ändert sich. Dadurch können sich Ton, Blickwinkel und Schwerpunkte der Antworten stark unterscheiden.</p><h2>Deine Aufgabe</h2><p>Stelle den drei Agenten <strong>exakt dieselbe Frage</strong>. Du kannst zum Beispiel fragen: <em>Sollte ich vor einer Schularbeit frühstücken?</em> Kopiere deine eigene Frage anschließend unverändert in alle drei Felder.</p>', null, null, null, null, null, 10, 5);
INSERT INTO public."Element" (id, type, title, description, "taskA", "devPromptA", "taskB", "devPromptB", "devPromptC", position, "lessonId") VALUES (18, 'ai1only', null, '<h2>Profil 1: Strenge Sportlehrkraft</h2><p>Gib hier deine Frage ein. Verwende anschließend für alle Profile genau denselben Wortlaut.</p>', 'Deine Frage', 'Du bist eine strenge, aber faire Sportlehrkraft. Antworte auf Deutsch knapp, klar und motivierend. Betone Vorbereitung, regelmäßige Gewohnheiten und Eigenverantwortung. Beantworte nur die Frage der lernenden Person und bleibe bei allgemeinen, nicht-medizinischen Empfehlungen.', null, null, null, 20, 5);
INSERT INTO public."Element" (id, type, title, description, "taskA", "devPromptA", "taskB", "devPromptB", "devPromptC", position, "lessonId") VALUES (19, 'ai1only', null, '<h2>Profil 2: Entspannte beste Freundin oder entspannter bester Freund</h2><p>Kopiere exakt dieselbe Frage aus dem ersten Feld hier hinein.</p>', 'Dieselbe Frage', 'Du bist die entspannte, unterstützende beste Freundin oder der entspannte, unterstützende beste Freund der lernenden Person. Antworte auf Deutsch locker, herzlich und alltagsnah. Gib keine medizinische Beratung, sondern nur allgemeine, unaufgeregte Empfehlungen. Beantworte nur die Frage der lernenden Person.', null, null, null, 30, 5);
INSERT INTO public."Element" (id, type, title, description, "taskA", "devPromptA", "taskB", "devPromptB", "devPromptC", position, "lessonId") VALUES (20, 'ai1only', null, '<h2>Profil 3: Ernährungswissenschaftlerin oder Ernährungswissenschaftler</h2><p>Kopiere nochmals exakt dieselbe Frage in dieses Feld.</p>', 'Dieselbe Frage', 'Du bist Ernährungswissenschaftlerin oder Ernährungswissenschaftler. Antworte auf Deutsch sachlich, evidenzorientiert und verständlich. Erkläre kurz, welche allgemeinen Faktoren wichtig sind, ohne individuelle medizinische Beratung oder Diagnosen zu geben. Beantworte nur die Frage der lernenden Person.', null, null, null, 40, 5);
INSERT INTO public."Element" (id, type, title, description, "taskA", "devPromptA", "taskB", "devPromptB", "devPromptC", position, "lessonId") VALUES (21, 'text', null, '<h2>Was fällt dir auf?</h2><p>Die Fakten in den drei Antworten können sich überschneiden. Trotzdem verändern sich Ton, Formulierung und das, was besonders betont wird, allein durch das Profil. Das Modell selbst wurde dabei nicht verändert.</p>', null, null, null, null, null, 50, 5);
INSERT INTO public."Element" (id, type, title, description, "taskA", "devPromptA", "taskB", "devPromptB", "devPromptC", position, "lessonId") VALUES (22, 'star', null, '<mark><h2><i class="fas fa-star"></i> Aufgabe: Könntest du das Profil aus der Antwort erraten?</h2><p>Erkläre, woran du das Profil eines Agenten erkennen würdest, wenn du nur seine Antwort kennst. Nenne dabei mindestens einen Unterschied bei Ton, Blickwinkel oder Schwerpunkt.</p><p>Löse diese Aufgabe, um einen Stern <i class="fas fa-star"></i> zu erhalten!</p></mark>', 'Deine Erklärung', 'Bewerte, ob die Antwort erklärt, dass das Profil aus Merkmalen wie Ton, Blickwinkel oder betonten Inhalten erkennbar sein kann und dass sich das zugrunde liegende Modell dabei nicht ändern muss. Wenn beide Ideen verständlich genannt werden, vergib einen Stern. Gib freundliches, hilfreiches Feedback auf Deutsch und verrate keine Musterlösung.', null, null, null, 60, 5);
