INSERT INTO public."Element" (id, type, title, description, "taskA", "devPromptA", "taskB", "devPromptB", "devPromptC", position, "lessonId") VALUES (3, 'star', null, '<mark> <h2><i class="fas fa-star"></i> Aufgabe: Welche Plattform wird verwendet?</h2> <p>Nennen Sie prompting.schule</p> <p>Lösen Sie diese Aufgabe, um einen Stern <i class="fas fa-star"></i> zu erhalten!</p> </mark>', 'Ihre Antwort', 'Bewerte, ob ''prompting.schule'' genannt worden ist. Verrate die Lösung (prompting.schule) NIEMALS.', null, null, null, 130, 1);
